Base class for parameterized functions to be used in Kedro nodes.

Example:
    # nodes.py
    class MyFunc(NodeFunc):
        p1: ...
        p2: ...

        def __call__(self, x, y):
            # process inputs `(x, y)` using params `(self.p1, self.p2)` and return something

    # parameters.yml
    nodes:
        my_func: {p1: ..., p2: ...}

    # pipeline.py
    def create_pipeline(config):
        my_func = MyFunc.parse_obj(config["parameters"]["nodes"]["my_func"])
        # Alternatively: my_func = MyFunc.default_parser(config)

        return Pipeline([
            MyFunc.to_node(inputs=[...], outputs=...),
        ])

    # pipeline_registry.py
    def register_pipelines():
        return {
            "my_pipeline": pipeline_factory(create_pipeline),
        }

Functional results paginator.

Example:
    page_size, max_results = 3, 9

    def get_page(token):
        data = range(token := token or 0, new_token := token + page_size)
        return Page(new_token if new_token < max_results else None, data)

    for x in Paginator(get_page).map_with(lambda x: x + 1):
        print(x)  # 1, 2, 3, 4... 9
